        status: 'check-it',
        confidence: 'medium',
        message: `Auth configured: ${providerName} but env example missing vars: ${missing.join(', ')}`,
        findings: missing.map(v => ({ file: envCandidates[0] || '.env.example', issue: `Missing expected env var: ${v}` }))
